/* Luxury Editorial — Embossed Minimalism */

/* Section heading: uppercase tracking, gold underline */
[data-section] h4,
[data-section] h5 {
  letter-spacing: 0.18em;
  text-transform: uppercase;
  font-weight: 600;
}

/* Gold accent on list markers */
li::marker {
  color: #D4AF37;
}

/* Name: editorial spacing */
h1 {
  letter-spacing: 0.06em;
}

/* Headline subtitle */
h2 {
  letter-spacing: 0.12em;
  text-transform: uppercase;
  font-size: 0.7rem;
  opacity: 0.7;
}

/* No rounded corners anywhere */
* {
  border-radius: 0 !important;
}

/* Refined link underlines */
a {
  text-decoration: none;
  border-bottom: 1px solid #D4AF37;
  transition: opacity 0.3s ease;
}
a:hover {
  opacity: 0.7;
}

/* Skill keywords: clean flat tags */
.rounded-sm, .rounded, .rounded-md, .rounded-lg {
  border-radius: 0 !important;
}

/* Subtle top-border section dividers */
section + section {
  border-top: 1px solid rgba(0,0,0,0.06);
  padding-top: 12px;
}
